1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	};
7	
8	export function quote(input: { customer: { yearsWithMHPCO: number; previousContract: boolean }; items: { type: string }[] }): number {
9	  if (input.items.length === 0) return PROCESSING_FEE;
10	  const basePremium = BASE_PREMIUM_BY_TYPE[input.items[0].type];
11	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
12	  return basePremium + firstInsurance + PROCESSING_FEE;
13	}
